import{_ as l,o as a,c as r,ae as e}from"./chunks/framework.DAK3ioSj.js";const S=JSON.parse('{"title":"Skills 技术分类体系","description":"","frontmatter":{"title":"Skills 技术分类体系"},"headers":[],"relativePath":"radar/01-taxonomy.md","filePath":"radar/01-taxonomy.md"}'),i={name:"radar/01-taxonomy.md"};function o(n,t,d,s,h,k){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="skills-技术分类体系" tabindex="-1">Skills 技术分类体系 <a class="header-anchor" href="#skills-技术分类体系" aria-label="Permalink to &quot;Skills 技术分类体系&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v2.0 · <strong>更新日期</strong>: 2026-05-12 · <strong>状态</strong>: 业界真实产品视图</p></blockquote><hr><h2 id="一、6-大生命周期阶段" tabindex="-1">一、6 大生命周期阶段 <a class="header-anchor" href="#一、6-大生命周期阶段" aria-label="Permalink to &quot;一、6 大生命周期阶段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>英文</th><th>核心问题</th></tr></thead><tbody><tr><td>Skill 生成</td><td>Generation</td><td>如何高效构建高质量 Skill？</td></tr><tr><td>Skill 召回</td><td>Recall / Routing</td><td>如何精准匹配用户意图与 Skill？</td></tr><tr><td>Skill 执行</td><td>Execution</td><td>如何高效、稳定、可控地执行 Skill？</td></tr><tr><td>Skill 评测</td><td>Evaluation</td><td>如何量化评估 Skill 的效果？</td></tr><tr><td>Skill 优化</td><td>Optimization</td><td>如何基于数据持续改进 Skill？</td></tr><tr><td>Skill 管理</td><td>Management</td><td>如何治理大规模 Skill 库？</td></tr></tbody></table><hr><h2 id="二、业界成熟度总览" tabindex="-1">二、业界成熟度总览 <a class="header-anchor" href="#二、业界成熟度总览" aria-label="Permalink to &quot;二、业界成熟度总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>成熟度</th><th style="text-align:center;">综合评分</th><th>代表产品</th></tr></thead><tbody><tr><td><a href="./category-02-recall.html">Skill 召回</a></td><td>🟢 成熟期</td><td style="text-align:center;"><strong>0.65</strong></td><td>SkillRouter · AgentSkillOS · SkillNet</td></tr><tr><td><a href="./category-05-optimization.html">Skill 优化</a></td><td>🟡 成长期</td><td style="text-align:center;"><strong>0.59</strong></td><td>OpenSpace · Hermes · SkillClaw · MetaClaw · SkillRL</td></tr><tr><td><a href="./category-01-generation.html">Skill 生成</a></td><td>🟡 成长期</td><td style="text-align:center;"><strong>0.55</strong></td><td>Skill Creator · Skill Seekers · EvoSkills · Trace2Skill · SkillRL</td></tr><tr><td><a href="./category-04-evaluation.html">Skill 评测</a></td><td>🟡 成长期</td><td style="text-align:center;"><strong>0.47</strong></td><td>SkillsBench · SkillNet · EvoSkills · SkillRet · SkillForge</td></tr><tr><td><a href="./category-03-execution.html">Skill 执行</a></td><td>🟡 成长期</td><td style="text-align:center;"><strong>0.45</strong></td><td>OpenSpace · AgentSkillOS · Memento-Skills · SkCC</td></tr><tr><td><a href="./category-06-management.html">Skill 管理</a></td><td>🟡 成长期（边界）</td><td style="text-align:center;"><strong>0.40</strong></td><td>Vercel skills.sh · SkillNet · AgentSkillOS · Agent Skills 标准</td></tr></tbody></table><hr><h2 id="三、各阶段简介" tabindex="-1">三、各阶段简介 <a class="header-anchor" href="#三、各阶段简介" aria-label="Permalink to &quot;三、各阶段简介&quot;">​</a></h2><h3 id="_3-1-skill-生成" tabindex="-1">3.1 Skill 生成 <a class="header-anchor" href="#_3-1-skill-生成" aria-label="Permalink to &quot;3.1 Skill 生成&quot;">​</a></h3><p><strong>定义</strong>：从多源数据（文档 / 工单 / 轨迹 / 会话）中提取知识，转化为标准化的可复用 Skill。</p><p><strong>主流路径</strong>：失败驱动 · 文档转化 · 会话提取 · 轨迹蒸馏 · 领域工单挖掘 · GEPA 进化</p><p><a href="./category-01-generation.html">查看完整技术文档 →</a></p><h3 id="_3-2-skill-召回" tabindex="-1">3.2 Skill 召回 <a class="header-anchor" href="#_3-2-skill-召回" aria-label="Permalink to &quot;3.2 Skill 召回&quot;">​</a></h3><p><strong>定义</strong>：从 Skill 库中精准匹配最优 Skill（或多 Skill 组合）以满足用户意图。</p><p><strong>关键结论</strong>：SkillRouter 实证证明<strong>全文检索是不可绕过的必要条件</strong>（隐藏 Skill body 后准确率暴跌 31-44pp）。</p><p><a href="./category-02-recall.html">查看完整技术文档 →</a></p><h3 id="_3-3-skill-执行" tabindex="-1">3.3 Skill 执行 <a class="header-anchor" href="#_3-3-skill-执行" aria-label="Permalink to &quot;3.3 Skill 执行&quot;">​</a></h3><p><strong>定义</strong>：按 Skill 定义的逻辑完成全链路运行、状态管控与异常处理。</p><p><strong>核心痛点</strong>：跨场景适配度无法预判（领域差异 10×）、负增益归因空白。<strong>SkCC 已破局跨框架可移植性</strong>（SkIR 强类型 IR）。</p><p><a href="./category-03-execution.html">查看完整技术文档 →</a></p><h3 id="_3-4-skill-评测" tabindex="-1">3.4 Skill 评测 <a class="header-anchor" href="#_3-4-skill-评测" aria-label="Permalink to &quot;3.4 Skill 评测&quot;">​</a></h3><p><strong>定义</strong>：构建可量化、可复现的多维度指标，衡量 Skill 的效果、效率与安全性。</p><p><strong>最大缺口</strong>：<strong>过程遵从度评测</strong>和<strong>多 Skill 归因</strong>完全空白 —— 所有评测都是 pass/fail 结果导向的黑盒。</p><p><a href="./category-04-evaluation.html">查看完整技术文档 →</a></p><h3 id="_3-5-skill-优化" tabindex="-1">3.5 Skill 优化 <a class="header-anchor" href="#_3-5-skill-优化" aria-label="Permalink to &quot;3.5 Skill 优化&quot;">​</a></h3><p><strong>定义</strong>：基于执行数据、评测结果与用户反馈的持续迭代闭环。</p><p><strong>进化信号源分化</strong>：失败轨迹 · 协同进化 · 并行轨迹池 · 多用户经验 · 双环架构 · DSPy + GEPA · 三模式实时进化。</p><p><a href="./category-05-optimization.html">查看完整技术文档 →</a></p><h3 id="_3-6-skill-管理" tabindex="-1">3.6 Skill 管理 <a class="header-anchor" href="#_3-6-skill-管理" aria-label="Permalink to &quot;3.6 Skill 管理&quot;">​</a></h3><p><strong>定义</strong>：面向大规模 Skill 库的版本、安全、权限、治理体系。</p><p><strong>最大盲点</strong>：26.1% 社区 Skill 含安全漏洞，但<strong>没有任何自动化扫描工具</strong>。即便 Vercel skills.sh 90K+ Skill 分发标准已成熟，<strong>安全防御工具仍为零</strong>。</p><p><a href="./category-06-management.html">查看完整技术文档 →</a></p><hr><h2 id="四、参考资料" tabindex="-1">四、参考资料 <a class="header-anchor" href="#四、参考资料" aria-label="Permalink to &quot;四、参考资料&quot;">​</a></h2><ul><li>每个产品的引用论文 / 仓库见 <a href="./../">tech-*.md 详情页</a></li><li><a href="./02-projects.html">代表项目调研</a> — 按阶段聚合的产品索引</li><li><a href="./03-maturity.html">成熟度评估模型</a> — 评分维度与方法论</li></ul>',37)])])}const c=l(i,[["render",o]]);export{S as __pageData,c as default};
